'use strict';

/**
* Fill a double-precision floating-point strided array with linearly spaced numeric elements which increment by `1` starting from one.
*
* @module @stdlib/blas-ext-base-done-to
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import doneTo from '@stdlib/blas-ext-base-done-to';
*
* var x = new Float64Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* doneTo( x.length, x, 1 );
* // x => <Float64Array>[ 1.0, 2.0, 3.0, 4.0 ]
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import doneTo from '@stdlib/blas-ext-base-done-to';
*
* var x = new Float64Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* doneTo.ndarray( x.length, x, 1, 0 );
* // x => <Float64Array>[ 1.0, 2.0, 3.0, 4.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var doneTo;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	doneTo = main;
} else {
	doneTo = tmp;
}


// EXPORTS //

export default doneTo;

// exports: { "ndarray": "doneTo.ndarray" }
